/**
 * @output wp-admin/js/customize-controls-proxy.js
 *
 * @since CP-2.8.0
 */

/* global wp, updatedControls, _updatedControlsWatcher */

// Stub to avoid error messages generated by themes and plugins
if ( ! wp || ! wp.customize || ! wp.customize.bind ) {
    var wp = window.wp = window.wp || {};
    wp.customize = {
        control: {
			bind: function() {}
		},
        Menus: {
			MenuItemControl: function() {}
		}
    };
    wp.customize.bind = function() {};
}

// Send data to iframe
window._previewSenders = {};
window._customizePublishing = false;
window._cpDirtySettings = {};

window.sendSettingToPreview = function( id, value ) {
    var iframe, src, match;

    if ( window._customizePublishing ) {
		return;
	}

    iframe = document.querySelector( '#customize-preview iframe' );
    if ( ! iframe || ! iframe.contentWindow ) {
		return;
	}

    src = iframe.src || '';
    match = src.match( /customize_messenger_channel=([^&]+)/ );
    if ( ! match ) {
		return;
	}

    iframe.contentWindow.postMessage(
        JSON.stringify( {
            channel: match[1],
            type: 'setting',
            data: [ id, value ]
        } ),
        location.origin
    );
};

window.sendCustomizedToPreview = function() {
    var iframe, src, match;

    if ( window._customizePublishing ) {
		return;
	}

    iframe = document.querySelector( '#customize-preview iframe' );
    if ( ! iframe || ! iframe.contentWindow ) {
		return;
	}

    src = iframe.src || '';
    match = src.match( /customize_messenger_channel=([^&]+)/ );
    if ( ! match ) {
		return;
	}

    iframe.contentWindow.postMessage(
        JSON.stringify( {
            channel: match[1],
            type:    'customized',
            data:    window._cpDirtySettings
        } ),
        location.origin
    );
};

window.updatedControls = window.updatedControls || {};

window._updatedControlsWatcher = new Proxy( window.updatedControls, {
    set: function( target, key, value ) {
        target[ key ] = value;
        window._cpDirtySettings[ key ] = value;

        if ( ! window._previewSenders[ key ] ) {
            window._previewSenders[ key ] = _.debounce( function() {
                window.sendSettingToPreview( key, target[ key ] );
            }, 300 );
        }

        window._previewSenders[ key ]();
        window.sendCustomizedToPreview();

        return true;
    }
} );
window.updatedControls = window._updatedControlsWatcher;
